```c
#include <pthread.h>
#include <queue>

std::priority_queue<int, std::vector<int>, std::greater<int>> waiting_threads;

void *allocate(int size) {
    pthread_mutex_lock(&m);
    while (bytesLeft < size && !waiting_threads.empty()) {
        int required_size = waiting_threads.top();
        if (required_size <= bytesLeft) {
