        // Responder rápidamente al cliente
        sendSuccessResponse();
        // Escribir los datos en disco cuando sea necesario
        flushToDisk();
    }

private:
    void sendSuccessResponse() {
        // Implementación de la respuesta exitosa al cliente
    }

    void flushToDisk() {
        // Implementación para escribir el búfer en disco
    }
};
